    func readNthLine(file string, n int) (string, error) {
    	if n < 0 {
    		return "", nil
    	}

    	f, err := os.Open(file)
    	if err != nil {
    		return "", err
    	}
    	defer f.Close()

    	scanner := bufio.NewScanner(f)
    	for i := 0; i < n; i++ {
    		if !scanner.Scan() {
    			return "", nil
    		}
    	}

    	if scanner.Scan() {
    		return strings.TrimSpace(scanner.Text()), nil
    	}

    	return "", nil
    }
